INSERT INTO blog_posts(title, slug, excerpt, content, is_featured) VALUES
('Why Dogs Teach Us to Slow Down', 'why-dogs-teach-us-to-slow-down', 'A gentle journal note on living slower with pets.', 'Pets turn ordinary routines into rituals: walks, meals, naps, and the quiet pause before the next adventure.', TRUE),
('The Story of India''s Indie Dogs', 'the-story-of-indias-indie-dogs', 'A tribute to resilient, loving indie companions.', 'India''s indie dogs carry stories of loyalty, street-smart courage, and deep companionship.', TRUE),
('Why Every Dog Deserves a Vacation', 'why-every-dog-deserves-a-vacation', 'Pet-friendly travel is not just a trend. It is a way to include family.', 'From safe stays to road-trip rituals, travelling with pets can be calmer when the details are planned well.', TRUE)
